Lookup time: 45 ns/lookup
False positive rate: 0.8% (8,000 false positives out of 1M)

Memory reduction: 10.7× (128 MB → 12 MB)
Speedup: 3.3× (150 ns → 45 ns)
В 10,7 раза меньше памяти
и
в 3,3 раза быстрее
, при этом всего 0,8% ложноположительных результатов (то есть повторного краулинга нескольких страниц).
В этой главе мы поговорим о вероятностных структурах данных, которые позволяют в обмен на снижение точности сэкономить огромные объёмы памяти.
Что нам рассказывают в учебниках
Фильтр Блума
— это эффективно использующая пространство вероятностная структура данных, проверяющая, находится ли элемент в множестве.
Свойства
:
Отсутствие ложноотрицательных результатов
: если он говорит «нет в множестве», то элемента точно нет
Возможные ложноположительные результаты
: если он говорит «есть в множестве», то может ошибаться
Эффективное использование пространства
: использует биты вместо хранения полных элементов
Высокая скорость
: O(k), где k — количество хэш-функций (обычно 3-10)
Что нам говорят учебники: «Используйте фильтры Блума, когда вас устраивает наличие ложноположительных результатов и есть необходимость экономии памяти».
Проверка реальностью: как работают фильтры Блума
Базовая структура
Фильтр Блума — это битовый массив размера m и k хэш-функций:
typedef struct {
 uint64_t *bits; // Битовый массив
 size_t m; // Количество бит
 int k; // Количество хэш-функций
} bloom_filter_t;

bloom_filter_t *bloom_create(size_t m, int k) {
 bloom_filter_t *bf = malloc(sizeof(bloom_filter_t));
 bf->m = m;
 bf->k = k;
 bf->bits = calloc((m + 63) / 64, sizeof(uint64_t));
 return bf;
}
Операция вставки
Хэшируем элемент k раз, задаём k бит:
void bloom_insert(bloom_filter_t *bf, const char *element) {
 for (int i = 0; i < bf->k; i++) {
 uint64_t hash = hash_function(element, i);
 size_t bit_pos = hash % bf->m;

 size_t word = bit_pos / 64;
 size_t bit = bit_pos % 64;
 bf->bits[word] |= (1UL << bit);
 }
}
Операция поиска
Хэшируем элемент k раз, проверяем, все ли k бит заданы:
bool bloom_contains(bloom_filter_t *bf, const char *element) {
 for (int i = 0; i < bf->k; i++) {
 uint64_t hash = hash_function(element, i);
 size_t bit_pos = hash % bf->m;

 size_t word = bit_pos / 64;
 size_t bit = bit_pos % 64;

 if (!(bf->bits[word] & (1UL << bit))) {
 return false; // Точно нет в множестве
 }
 }
 return true; // Вероятно, находится в множестве (может быть ложноположительным результатом)
}
Почему возникают ложноположительные результаты
После вставки большого количества элементов многие биты имеют значение 1. Поиск случайно может обнаружить, что заданы все k бит, даже если элемент не вставлялся.
Пример
:
Вставка "foo": задаёт биты 5, 12, 23
Вставка "bar": задаёт биты 12, 18, 30
Вставка "baz": задаёт биты 5, 18, 42

Поиск "xyz": хэшируется в биты 5, 12, 18
 Все три бита заданы (другими элементами)!
 Ложноположительный результат!
Выбор параметров: m и k
Частота ложноположительных результатов зависит от:
m
: количества бит
k
: количества хэш-функций
n
: количества вставленных элементов
Оптимальное k
: k = (m/n) × ln(2) ≈ 0,693 × (m/n)
Частота ложноположительных результатов
: p ≈ (1 - e^(-kn/m))^k
Пример расчёта
Для 1 миллиона URL с 1% ложноположительных результатов:
Целевые показатели: p = 0,01, n = 1000000

Вычисляем m:
 m = -n × ln(p) / (ln(2))^2
 m = -1000000 × ln(0,01) / 0,48
 m ≈ 9585058 бит ≈ 1,2 МБ

Оптимальное k:
 k = (m/n) × ln(2)
 k = 9,6 × 0,693
 k ≈ 7 хэш-функций
То есть для 1 миллиона URL с 1% ложноположительных результатов нужно всего
1,2 МБ и 7 хэш-функций
.
Сравните это с хэш-таблицей:
96 МБ
(в 80 раз больше памяти!).
Реализация фильтра Блума с оптимальным использованием кэша
Наивная реализация обладает плохим поведением при работе с кэшем: k хэш-функций получают доступ к k произвольным адресам памяти.
Проблема: произвольный доступ к памяти
// Наивное решение: k произвольных операций доступа
for (int i = 0; i < k; i++) {
 size_t bit_pos = hash(element, i) % m;
 // Каждый bit_pos случаен → промах кэша!
}
При k=7 получается
7 промахов кэша на одну операцию поиска
!
Решение: блочный фильтр Блума
Разбиваем битовый массив на блоки, используем по k бит в одном блоке:
#define BLOCK_SIZE 512 // 512 бит = 64 байт = 1 линия кэша

typedef struct {
 uint64_t *bits;
 size_t num_blocks;
 int k;
} blocked_bloom_t;

bool blocked_bloom_contains(blocked_bloom_t *bf, const char *element) {
 uint64_t hash = hash_function(element, 0);
 size_t block = hash % bf->num_blocks;

 // Все k бит находятся в одном блоке (одна линия кэша!)
 uint64_t *block_ptr = &bf->bits[block * (BLOCK_SIZE / 64)];

 for (int i = 0; i < bf->k; i++) {
 uint64_t h = hash_function(element, i);
 size_t bit_pos = h % BLOCK_SIZE;
 size_t word = bit_pos / 64;
 size_t bit = bit_pos % 64;

 if (!(block_ptr[word] & (1UL << bit))) {
 return false;
 }
 }
 return true;
}
Почему это помогает
:
Все k бит находятся в одной линии кэша
1 промах кэша вместо k промахов
Для k=7 промахов кэша становится в 7 раз меньше
Бенчмарк
Тест: 1 миллион операций поиска в фильтре Блума (k=7, m=10 миллионов бит)

Наивный фильтр Блума:
 Промахи кэша: 7 миллионов (7 на одну операцию)
 Такты: 450 миллионов
 Время: 375 мс

Блочный фильтр Блума (512-битные блоки):
 Промахи кэша: 1 миллион (1 на одну операцию)
 Такты: 85 миллионов
 Время: 71 мс
 Ускорение: 5,3×
Ускорение в 5,3 раза
благодаря одному лишь повышению локальности кэша!
Продвинутый уровень: фильтр Блума с подсчётом
Стандартные фильтры Блума не могут удалять элементы (нельзя сбросить бит — он может быть общим с другими элементами).
В
фильтрах Блума с подсчётом
вместо битов используются счётчики:
typedef struct {
 uint8_t *counters; // 4-битные счётчики (0-15)
 size_t m;
 int k;
} counting_bloom_t;

void counting_bloom_insert(counting_bloom_t *bf, const char *element) {
 for (int i = 0; i < bf->k; i++) {
 size_t pos = hash(element, i) % bf->m;
 if (bf->counters[pos] < 15) { // Защита от переполнения
 bf->counters[pos]++;
 }
 }
}

void counting_bloom_delete(counting_bloom_t *bf, const char *element) {
 for (int i = 0; i < bf->k; i++) {
 size_t pos = hash(element, i) % bf->m;
 if (bf->counters[pos] > 0) {
 bf->counters[pos]--;
 }
 }
}
Компромисс
: использует в 4 раза больше памяти (4 бита на счётчик вместо 1 бита), но поддерживает удаление.
Пример из реального мира: безопасный браузинг Google Chrome
Перед отправкой URL на серверы Google браузер Chrome проверяет его на потенциальную зловредность при помощи фильтра Блума.
Проблема
Chrome необходимо сверить миллионы URL с чёрным списком зловредных сайтов:
В чёрном списке около миллиона элементов
Отправлять каждый URL в Google нельзя (конфиденциальность + задержки)
Ограниченная память на клиенте
Решение
Двухэтапная проверка
:
Локальный фильтр Блума
(быстрый, занимает мало памяти):
1 миллион элементов, 1% ложноположительных результатов
Память: 1,2 МБ
Поиск: <1 мкс
Если фильтр Блума сообщает «элемента нет в множестве» → безопасно, не обращаемся к серверу
Проверка на сервере
(медленная и точная):
Если фильтр Блума сообщает «элемент может быть в множестве» → обращаемся на сервер за подтверждением
Проверки сервером требует всего 1% URL (ложноположительные результаты)
Результат
:
99% URL проверяется локально (сетевые задержки отсутствуют)
1,2 МБ памяти (против 80 МБ для полной хэш-таблицы)
Сохранение конфиденциальности (на сервер отправляются только подозрительные URL)
Другие вероятностные структуры данных
1. Count-Min Sketch
Оценивает частоту элементов в потоке.
typedef struct {
 int **counters; // Массив счётчиков d × w
 int d; // Количество хэш-функций
 int w; // Ширина каждой строки
} count_min_sketch_t;

void cms_increment(count_min_sketch_t *cms, const char *element) {
 for (int i = 0; i < cms->d; i++) {
 int pos = hash(element, i) % cms->w;
 cms->counters[i][pos]++;
 }
}

int cms_estimate(count_min_sketch_t *cms, const char *element) {
 int min_count = INT_MAX;
 for (int i = 0; i < cms->d; i++) {
 int pos = hash(element, i) % cms->w;
 if (cms->counters[i][pos] < min_count) {
 min_count = cms->counters[i][pos];
 }
 }
 return min_count; // Оценка (всегда ≥ истинного количества)
}
Сценарий использования
: анализ сетевого трафика (подсчёт частоты пакетов без хранения всех пакетов).
Память
: O(d × w) вместо O(n) в случае точного подсчёта.
2. HyperLogLog
Оценивает кардинальность (количество уникальных элементов) в потоке.
typedef struct {
 uint8_t *registers; // m регистров
 int m; // Количество регистров (степень двойки)
} hyperloglog_t;

void hll_add(hyperloglog_t *hll, const char *element) {
 uint64_t hash = hash_function(element);
 int j = hash & (hll->m - 1); // Первые log2(m) бит
 int w = __builtin_clzll(hash >> __builtin_ctz(hll->m)) + 1; // Нули в начале

 if (w > hll->registers[j]) {
 hll->registers[j] = w;
 }
}

size_t hll_estimate(hyperloglog_t *hll) {
 double sum = 0;
 for (int i = 0; i < hll->m; i++) {
 sum += 1.0 / (1 << hll->registers[i]);
 }
 double alpha = 0.7213 / (1 + 1.079 / hll->m); // Коррекция перекоса
 return (size_t)(alpha * hll->m * hll->m / sum);
}
