 size_t i2 = (i1 ^ hash_function(&fp, 0)) % cf->num_buckets;

 // Проверяем бакет i1
 for (int j = 0; j < BUCKET_SIZE; j++) {
 if (cf->buckets[i1].fingerprint[j] == fp) {
 return true;
 }
 }

 // Проверяем бакет i2
 for (int j = 0; j < BUCKET_SIZE; j++) {
 if (cf->buckets[i2].fingerprint[j] == fp) {
